from fastapi import FastAPI, Request, HTTPException
from fastapi.responses import StreamingResponse
from pydantic import BaseModel, Field
from typing import AsyncGenerator
import openai
import asyncio
import json
import os
from dotenv import load_dotenv

# Load environment variables
load_dotenv()

app = FastAPI()

# Configure OpenAI API key
openai.api_key = os.getenv("OPENAI_API_KEY")

class DocumentRequest(BaseModel):
    text: str = Field(..., min_length=10, max_length=10000, description="Text to summarize")

class OpenAIError(Exception):
    """Custom exception for OpenAI API errors"""
    pass

async def stream_summary(text: str) -> AsyncGenerator[str, None]:
    """Generate SSE formatted summary stream"""
    try:
        # Create chat completion with streaming
        stream = await openai.ChatCompletion.acreate(
            model="gpt-3.5-turbo",
            messages=[
                {
                    "role": "system",
                    "content": "You are a helpful assistant that summarizes text in exactly 3 bullet points. Be concise and informative."
                },
                {
                    "role": "user",
                    "content": f"Summarize the following text in exactly 3 bullet points:\n\n{text}"
                }
            ],
            stream=True,
            temperature=0.3,
            max_tokens=200
        )

        # Stream the response chunks
        async for chunk in stream:
            if chunk.choices[0].delta.get("content"):
                content = chunk.choices[0].delta.content
                # Send SSE formatted data
                yield f"data: {json.dumps({'content': content})}\n\n"
                await asyncio.sleep(0.01)  # Small delay for smoother streaming

        # Send completion signal
        yield f"data: {json.dumps({'done': True})}\n\n"

    except openai.error.OpenAIError as e:
        error_msg = f"OpenAI API error: {str(e)}"
        yield f"data: {json.dumps({'error': error_msg})}\n\n"
    except Exception as e:
        error_msg = f"Unexpected error: {str(e)}"
        yield f"data: {json.dumps({'error': error_msg})}\n\n"

@app.post("/summarize")
async def summarize_document(request: DocumentRequest):
    """
    Summarize a document in 3 bullet points using OpenAI API.
    Returns a streaming response using Server-Sent Events.
    """
    try:
        # Validate input
        if not request.text.strip():
            raise HTTPException(status_code=400, detail="Text cannot be empty")

        # Return streaming response
        return StreamingResponse(
            stream_summary(request.text),
            media_type="text/event-stream",
            headers={
                "Cache-Control": "no-cache",
                "Connection": "keep-alive",
                "X-Accel-Buffering": "no"  # Disable nginx buffering if behind nginx
            }
        )

    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Internal server error: {str(e)}")

@app.get("/health")
async def health_check():
    """Health check endpoint"""
    return {"status": "healthy"}

# Alternative implementation with more granular error handling
@app.post("/summarize/v2")
async def summarize_document_v2(request: DocumentRequest):
    """
    Enhanced version with better error handling and validation.
    """
    try:
        # Additional validation
        if len(request.text.split()) < 5:
            raise HTTPException(
                status_code=400, 
                detail="Text must contain at least 5 words for meaningful summarization"
            )

        # Check if OpenAI API key is configured
        if not openai.api_key:
            raise HTTPException(
                status_code=500, 
                detail="OpenAI API key not configured"
            )

        async def generate():
            try:
                # Send initial event
                yield f"data: {json.dumps({'status': 'started'})}\n\n"

                # Create chat completion with streaming
                stream = await openai.ChatCompletion.acreate(
                    model="gpt-3.5-turbo",
                    messages=[
                        {
                            "role": "system",
                            "content": "You are a helpful assistant that summarizes text in exactly 3 bullet points. Format each bullet point on a new line starting with '•'."
                        },
                        {
                            "role": "user",
                            "content": f"Summarize the following text in exactly 3 bullet points:\n\n{request.text}"
                        }
                    ],
                    stream=True,
                    temperature=0.3,
                    max_tokens=200,
                    presence_penalty=0.0,
                    frequency_penalty=0.0
                )

                # Stream the response chunks
                async for chunk in stream:
                    if chunk.choices[0].delta.get("content"):
                        content = chunk.choices[0].delta.content
                        yield f"data: {json.dumps({'content': content})}\n\n"
                        await asyncio.sleep(0.01)

                # Send completion event
                yield f"data: {json.dumps({'status': 'completed'})}\n\n"

            except openai.error.RateLimitError as e:
                yield f"data: {json.dumps({'error': 'Rate limit exceeded. Please try again later.'})}\n\n"
            except openai.error.AuthenticationError as e:
                yield f"data: {json.dumps({'error': 'Invalid API key. Please check your OpenAI API key.'})}\n\n"
            except openai.error.InvalidRequestError as e:
                yield f"data: {json.dumps({'error': f'Invalid request: {str(e)}'})}\n\n"
            except openai.error.APIConnectionError as e:
                yield f"data: {json.dumps({'error': 'Failed to connect to OpenAI API. Please check your internet connection.'})}\n\n"
            except openai.error.OpenAIError as e:
                yield f"data: {json.dumps({'error': f'OpenAI API error: {str(e)}'})}\n\n"
            except Exception as e:
                yield f"data: {json.dumps({'error': f'Unexpected error: {str(e)}'})}\n\n"

        return StreamingResponse(
            generate(),
            media_type="text/event-stream",
            headers={
                "Cache-Control": "no-cache",
                "Connection": "keep-alive",
                "X-Accel-Buffering": "no"
            }
        )

    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Internal server error: {str(e)}")

# Client-side example (for testing)
@app.get("/test-client")
async def test_client():
    """Simple HTML client for testing the SSE endpoint"""
    return """
    <!DOCTYPE html>
    <html>
    <head>
        <title>SSE Test Client</title>
    </head>
    <body>
        <h1>Document Summarizer</h1>
        <textarea id="text" rows="10" cols="50" placeholder="Enter text to summarize..."></textarea><br>
        <button onclick="summarize()">Summarize</button>
        <div id="output"></div>

        <script>
            async function summarize() {
                const text = document.getElementById('text').value;
                const output = document.getElementById('output');
                output.innerHTML = 'Summarizing...';

                const response = await fetch('/summarize/v2', {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({ text: text })
                });

                const reader = response.body.getReader();
                const decoder = new TextDecoder();

                while (true) {
                    const { done, value } = await reader.read();
                    if (done) break;

                    const chunk = decoder.decode(value);
                    const lines = chunk.split('\\n');

                    for (const line of lines) {
                        if (line.startsWith('data: ')) {
                            const data = JSON.parse(line.substring(6));
                            if (data.content) {
                                output.innerHTML += data.content;
                            } else if (data.error) {
                                output.innerHTML += `<br><span style="color: red">Error: ${data.error}</span>`;
                            } else if (data.status === 'completed') {
                                output.innerHTML += '<br><span style="color: green">✓ Completed</span>';
                            }
                        }
                    }
                }
            }
        </script>
    </body>
    </html>
    """

if __name__ == "__main__":
    import uvicorn
    uvicorn.run(app, host="0.0.0.0", port=8000)
